class Solution {
    public int findKthNumber(int n, int k) {
        long cur = 1;
        k--;
        while (k > 0) {
            long step = 0, first = cur, last = cur + 1;
            while (first <= n) {
                step += Math.min(n + 1, last) - first;
                first *= 10;
                last *= 10;
            }
            if (k < step) {
                k--;
                cur *= 10;
            } else {
                k -= step;
                cur++;
            }
        }
        return (int) cur;
    }
}
